blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie poznasz <strong>get-passive</strong>, mówioną wersję strony biernej. Podkreśla <strong>zmianę stanu, wydarzenia lub zaskoczenia</strong> i często ma wydźwięk emocjonalny.",
    "rules": [
        {
            "label": "Bądź pasywny",
            "color": "blue",
            "text": "<strong>be + V3</strong> — neutralny, formalny:",
            "example": "He was fired last week."
        },
        {
            "label": "Uzyskaj pasywność",
            "color": "emerald",
            "text": "<strong>get + V3</strong> — konwersacyjny, dynamiczny:",
            "example": "He got fired last week."
        },
        {
            "label": "Cień",
            "color": "rose",
            "text": "Get-passive = wydarzenie, zmiana, niespodzianka:",
            "example": "They got married in June."
        }
    ]
}

{
    "title": "1. Struktura Get-pasywna",
    "intro": "Wzór: <strong>pobierz + imiesłów przeszły (V3)</strong>",
    "items": [
        {
            "label": "Formuła",
            "title": "zdobądź + V3",
            "subtitle": "get zamiast być w stronie biernej"
        },
        {
            "label": "czasy",
            "title": "uzyskać różni się w czasie",
            "subtitle": "dostać/dostaje/dostaje/dostanie/dostanie + V3"
        },
        {
            "label": "Styl",
            "title": "Rozmowny, nieformalny",
            "subtitle": "Częściej w mówionym języku angielskim"
        },
        {
            "label": "Cień",
            "title": "Wydarzenie, zmiana stanu",
            "subtitle": "Coś się wydarzyło (często niespodziewanie)"
        }
    ]
}

{
    "title": "2. Kiedy stosować Get-passive?",
    "sections": [
        {
            "label": "Nieoczekiwane wydarzenia",
            "color": "emerald",
            "description": "Kiedy coś <strong>zdarzy się nieoczekiwanie</strong>, przypadkowo.",
            "examples": [
                {
                    "en": "He got hit by a car.",
                    "ua": "Został potrącony przez samochód."
                },
                {
                    "en": "She got caught in the rain.",
                    "ua": "Złapała ją deszcz."
                },
                {
                    "en": "I got stuck in traffic.",
                    "ua": "Utknąłem w korku."
                }
            ]
        },
        {
            "label": "Negatywne zdarzenia",
            "color": "rose",
            "description": "Często w <strong>negatywnych, nieprzyjemnych</strong> sytuacjach.",
            "examples": [
                {
                    "en": "He got fired from his job.",
                    "ua": "Został wyrzucony z pracy."
                },
                {
                    "en": "She got hurt in the accident.",
                    "ua": "Została ranna w wypadku."
                },
                {
                    "en": "My phone got stolen.",
                    "ua": "Skradziono mi telefon."
                }
            ]
        },
        {
            "label": "Zmiana stanu",
            "color": "sky",
            "description": "Podkreśla <strong>przejście z jednego stanu do drugiego</strong>.",
            "examples": [
                {
                    "en": "They got married last year.",
                    "ua": "Pobrali się w zeszłym roku."
                },
                {
                    "en": "He got promoted to manager.",
                    "ua": "Awansował na menadżera."
                },
                {
                    "en": "The window got broken.",
                    "ua": "Okno pękło."
                }
            ]
        },
        {
            "label": "Pozytywne wydarzenia",
            "color": "amber",
            "description": "Czasami dla <strong>pozytywnych zmian</strong> — ale rzadziej.",
            "examples": [
                {
                    "en": "She got accepted to university.",
                    "ua": "Została przyjęta na uniwersytet."
                },
                {
                    "en": "He got selected for the team.",
                    "ua": "Został wybrany do zespołu."
                },
                {
                    "en": "I got invited to the party.",
                    "ua": "Zostałem zaproszony na imprezę."
                }
            ]
        }
    ]
}

{
    "title": "3. Typowe wyrażenia z Get-passive",
    "sections": [
        {
            "label": "Życie osobiste",
            "color": "emerald",
            "description": "Wyrażenia na temat <strong>osobistych wydarzeń i relacji</strong>.",
            "examples": [
                {
                    "en": "get married",
                    "ua": "wyjść za mąż"
                },
                {
                    "en": "get divorced",
                    "ua": "rozpadać się"
                },
                {
                    "en": "get engaged",
                    "ua": "bezpieczny"
                }
            ]
        },
        {
            "label": "Praca",
            "color": "blue",
            "description": "Wyrażenia na temat <strong>pracy i kariery</strong>.",
            "examples": [
                {
                    "en": "get hired",
                    "ua": "zostać zatrudnionym"
                },
                {
                    "en": "get fired",
                    "ua": "zostać zwolniony"
                },
                {
                    "en": "get promoted",
                    "ua": "dostać awans"
                },
                {
                    "en": "get paid",
                    "ua": "dostać pensję"
                }
            ]
        },
        {
            "label": "Kłopoty",
            "color": "rose",
            "description": "Wyrażenia dotyczące <strong>problemów i kłopotów</strong>.",
            "examples": [
                {
                    "en": "get hurt",
                    "ua": "cierpieć"
                },
                {
                    "en": "get injured",
                    "ua": "doznać kontuzji"
                },
                {
                    "en": "get lost",
                    "ua": "Spadaj"
                },
                {
                    "en": "get stuck",
                    "ua": "wkopać się"
                }
            ]
        },
        {
            "label": "Inne sytuacje",
            "color": "amber",
            "description": "Inne <strong>wyrażenia regularne</strong> z funkcją get-passive.",
            "examples": [
                {
                    "en": "get caught",
                    "ua": "zostać złapanym"
                },
                {
                    "en": "get arrested",
                    "ua": "zostać aresztowanym"
                },
                {
                    "en": "get killed",
                    "ua": "zostać zabitym"
                },
                {
                    "en": "get dressed",
                    "ua": "ubierz się"
                }
            ]
        }
    ]
}

{
    "title": "4. Get-bierny w różnych czasach",
    "sections": [
        {
            "label": "Czas teraźniejszy prosty",
            "color": "emerald",
            "description": "<strong>get/gets + V3</strong> — regularne działania, nawyki.",
            "examples": [
                {
                    "en": "He often gets invited to parties.",
                    "ua": "Często jest zapraszany na imprezy."
                },
                {
                    "en": "People get hurt in accidents every day.",
                    "ua": "Codziennie ludzie doznają obrażeń w wypadkach."
                }
            ]
        },
        {
            "label": "Czas przeszły prosty",
            "color": "blue",
            "description": "<strong>otrzymałem + V3</strong> — określone wydarzenia w przeszłości.",
            "examples": [
                {
                    "en": "She got promoted last month.",
                    "ua": "Awansowała w zeszłym miesiącu."
                },
                {
                    "en": "They got married in 2020.",
                    "ua": "Pobrali się w 2020 roku."
                }
            ]
        },
        {
            "label": "Przyszły",
            "color": "sky",
            "description": "<strong>otrzyma + V3</strong> / <strong>otrzyma + V3</strong>.",
            "examples": [
                {
                    "en": "She will get paid tomorrow.",
                    "ua": "Jutro otrzyma wypłatę."
                },
                {
                    "en": "He is going to get fired if he is late again.",
                    "ua": "Jeśli ponownie się spóźni, zostanie zwolniony."
                }
            ]
        },
        {
            "label": "Czas teraźniejszy idealny",
            "color": "amber",
            "description": "<strong>ma/ma + V3</strong> to dotychczasowy wynik.",
            "examples": [
                {
                    "en": "She has got accepted to Harvard!",
                    "ua": "Została przyjęta na Harvard!"
                },
                {
                    "en": "I have got stuck in this traffic for an hour.",
                    "ua": "Utknąłem w tym korku na godzinę."
                }
            ]
        }
    ]
}

{
    "title": "5. Bądź pasywny vs bądź pasywny",
    "intro": "Porównanie standardowego pasywnego z get-passive:",
    "rows": [
        {
            "en": "be + V3",
            "ua": "Neutralny, formalny",
            "note": "The report was completed."
        },
        {
            "en": "get + V3",
            "ua": "Rozmowny, nieformalny",
            "note": "The report got completed."
        },
        {
            "en": "be + V3",
            "ua": "Stan lub wynik",
            "note": "Drzwi są zamknięte. (jednolita stawka)"
        },
        {
            "en": "get + V3",
            "ua": "Proces, zmiana",
            "note": "Drzwi się zamknęły. (akcja, wydarzenie)"
        },
        {
            "en": "be + V3",
            "ua": "Wszelkie konteksty",
            "note": "Zawsze pasuje."
        },
        {
            "en": "get + V3",
            "ua": "Często niespodziewane zdarzenia",
            "note": "Często negatywne, nieoczekiwane."
        }
    ],
    "warning": "📌 <strong>Bądź pasywny</strong> częściej w przypadku nieoczekiwanych, negatywnych lub dynamicznych wydarzeń!"
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Użycie get-passive w bardzo formalnym kontekście.",
            "wrong": "The contract got signed by the CEO. (formal)",
            "right": "✅ The contract was signed by the CEO."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie get + adjective i get + V3.",
            "wrong": "I got interesting.",
            "right": "✅ I got interested in the topic."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie wydarzenia ze stanem.",
            "wrong": "They were married last June. (opis stanu)",
            "right": "✅ They got married last June. (mówimy o wydarzeniu)"
        }
    ]
}
